import socket
import ipaddress
from flask import Flask, request

app = Flask(__name__)

# Define blocked IP ranges
def is_blocked_ip(ip_str):
    try:
        ip = ipaddress.ip_address(ip_str)
        # Loopback, link-local, private, unique local, unspecified
        if ip.is_private or ip.is_loopback or ip.is_link_local or ip.is_unspecified:
            return True
        # Check for RFC1918, RFC4193, RFC4291 (IPv6)
        blocked_networks = [
            ipaddress.ip_network('127.0.0.0/8'),
            ipaddress.ip_network('10.0.0.0/8'),
            ipaddress.ip_network('172.16.0.0/12'),
            ipaddress.ip_network('192.168.0.0/16'),
            ipaddress.ip_network('169.254.0.0/16'),
            ipaddress.ip_network('::1/128'),
            ipaddress.ip_network('fc00::/7'),
            ipaddress.ip_network('fe80::/10'),
        ]
        for network in blocked_networks:
            if ip in network:
                return True
        return False
    except ValueError:
        return True  # Invalid IP is blocked

def resolve_and_check(url):
    try:
        # Extract hostname from URL (assuming https:// prefix)
        hostname = url.replace('https://', '').split('/')[0]
        # Resolve hostname to IPs
        addr_info = socket.getaddrinfo(hostname, None, socket.AF_UNSPEC, socket.SOCK_STREAM)
        for info in addr_info:
            ip = info[4][0]
            if is_blocked_ip(ip):
                return False, f"Blocked IP: {ip}"
        return True, None
    except Exception as e:
        return False, str(e)

