    # Validate subdomain: only allow alphanumeric, hyphens, and dots
    if not subdomain:
        return "Invalid subdomain", 400

    # Strict validation: only [a-zA-Z0-9.-], no consecutive dots, no leading/trailing dots
    if not all(c.isalnum() or c in '-.' for c in subdomain):
